object Solution { def sessionize_events(events: Seq[Seq[Any]], timeout: Int): Seq[Seq[Any]] = { case class Session(start: Int, end: Int, count: Int); val open = scala.collection.mutable.Map[String, Session](); val closed = scala.collection.mutable.ArrayBuffer[Seq[Any]](); for (event <- events) { val timestamp = asInt(event(0)); val userId = event(1).toString; open.get(userId) match { case Some(session) if timestamp - session.end <= timeout => open(userId) = session.copy(end = timestamp, count = session.count + 1); case Some(session) => closed += Seq(userId, session.start, session.end, session.count); open(userId) = Session(timestamp, timestamp, 1); case None => open(userId) = Session(timestamp, timestamp, 1) } }; for ((userId, session) <- open) closed += Seq(userId, session.start, session.end, session.count); closed.toSeq.sortBy(row => (asInt(row(1)), row(0).toString)) }; private def asInt(value: Any): Int = value match { case n: Int => n; case n: Long => n.toInt; case n: Double => n.toInt; case _ => 0 } }
